func And(predicates ...predicate.InterfaceField) predicate.InterfaceField {
	return predicate.InterfaceField(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.InterfaceField) predicate.InterfaceField {
	return predicate.InterfaceField(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.InterfaceField) predicate.InterfaceField {
	return predicate.InterfaceField(sql.NotPredicates(p))
}
